+fn parse_input<T>(input: &serde_json::Value, operation: &str) -> FcpResult<T>
+where
+    T: DeserializeOwned,
+{
+    serde_json::from_value(input.clone()).map_err(|error| FcpError::InvalidRequest {
+        code: 1003,
+        message: format!("invalid {operation} input: {error}"),
+    })
+}
